export const crisisKeywords = [
  "suicide",
  "kill myself",
  "end my life",
  "no reason to live",
  "die",
  "i want to die"
];

export function isCrisisMessage(message) {
  return crisisKeywords.some(word =>
    message.toLowerCase().includes(word)
  );
}
